**核心原则：每个 goroutine 都必须有明确的退出路径。**

```iFace/tmp/memory.md#L1-1
package main

import (
    "context"
    "fmt"
    "sync"
    "time"
)

// WorkerPool 是一个无泄漏的 goroutine 池
type WorkerPool struct {
    workerCount int
    jobs        chan Job
    wg          sync.WaitGroup
    cancel      context.CancelFunc
    ctx         context.Context
}

type Job struct {
    ID   int
    Data string
}

func NewWorkerPool(ctx context.Context, workerCount int) *WorkerPool {
    ctx, cancel := context.WithCancel(ctx)
    p := &WorkerPool{
        workerCount: workerCount,
        jobs:        make(chan Job, workerCount*2), // 有缓冲，防止发送方阻塞
        cancel:      cancel,
        ctx:         ctx,
    }
    p.start()
    return p
}

func (p *WorkerPool) start() {
    for i := 0; i < p.workerCount; i++ {
        p.wg.Add(1)
        go p.worker(i)
    }
}

func (p *WorkerPool) worker(id int) {
    defer p.wg.Done() // 确保 wg 计数器正确递减
    for {
        select {
        case job, ok := <-p.jobs:
            if !ok {
                // channel 已关闭，正常退出
                fmt.Printf("worker %d: channel closed, exiting\n", id)
                return
            }
            p.processJob(job)
        case <-p.ctx.Done():
            // context 取消，优雅退出
            fmt.Printf("worker %d: context cancelled, exiting\n", id)
            return
        }
    }
}

func (p *WorkerPool) processJob(job Job) {
    // 使用带超时的 context 防止单个任务卡死 worker
    ctx, cancel := context.WithTimeout(p.ctx, 5*time.Second)
    defer cancel()
    _ = ctx
    // 实际处理逻辑...
    fmt.Printf("processing job %d\n", job.ID)
}

// Submit 提交任务，若 ctx 取消则放弃提交
func (p *WorkerPool) Submit(job Job) error {
    select {
    case p.jobs <- job:
        return nil
    case <-p.ctx.Done():
        return p.ctx.Err()
    }
}

// Shutdown 优雅关闭：停止接受新任务，等待存量任务完成
func (p *WorkerPool) Shutdown() {
    close(p.jobs) // 关闭 channel，worker 处理完剩余任务后退出
    p.wg.Wait()   // 等待所有 worker 退出
    p.cancel()    // 释放 context 资源
}

func main() {
    ctx := context.Background()
    pool := NewWorkerPool(ctx, 4)

    // 提交任务
    for i := 0; i < 10; i++ {
        pool.Submit(Job{ID: i, Data: fmt.Sprintf("data-%d", i)})
    }

    // 优雅关闭
    pool.Shutdown()
    fmt.Println("all workers exited, no goroutine leak")
}
```

**关键设计点：**

| 设计点 | 实现方式 | 防止的问题 |
|--------|---------|-----------|
| worker 有退出路径 | `ctx.Done()` + channel 关闭 | goroutine 永久阻塞 |
| 等待所有 worker 退出 | `sync.WaitGroup` | 主程序退出时 goroutine 强制终止 |
| 有缓冲 channel | `make(chan Job, N)` | 发送方不因消费慢而阻塞泄漏 |
| 单任务超时 | `context.WithTimeout` | 单个任务卡死整个 worker |
| Submit 监听 ctx | `select + ctx.Done()` | 关闭期间不阻塞提交方 |

**目标：实现一个 JSON 序列化工具，使热路径零堆分配。**

```iFace/tmp/memory.md#L1-1
package buffer

import (
    "encoding/json"
    "sync"
)

// pooledBuffer 包装 []byte，便于 sync.Pool 管理
type pooledBuffer struct {
    buf []byte
}

// bufPool 复用 pooledBuffer，避免频繁分配
var bufPool = sync.Pool{
    New: func() interface{} {
        // 预分配 4KB，覆盖大多数 JSON 响应大小
        return &pooledBuffer{
            buf: make([]byte, 0, 4096),
        }
    },
}

// MarshalJSON 序列化 v，返回 JSON 字节（调用方不应持有返回值超过本次请求）
// 使用完毕后应调用 Release 归还 buf
func MarshalJSON(v interface{}) ([]byte, func(), error) {
    pb := bufPool.Get().(*pooledBuffer)
    pb.buf = pb.buf[:0] // 重置长度，保留底层数组

    data, err := json.Marshal(v)
    if err != nil {
        pb.buf = pb.buf[:0]
        bufPool.Put(pb)
        return nil, nil, err
    }

    // 将序列化结果追加到复用 buf
    pb.buf = append(pb.buf, data...)

    // 返回 buf 的引用和释放函数
    release := func() {
        pb.buf = pb.buf[:0]
        bufPool.Put(pb)
    }

    return pb.buf, release, nil
}

// 使用示例
func handleRequest(w http.ResponseWriter, resp interface{}) {
    data, release, err := MarshalJSON(resp)
    if err != nil {
        http.Error(w, err.Error(), 500)
        return
    }
    defer release() // 确保归还

    w.Header().Set("Content-Type", "application/json")
    w.Write(data) // Write 内部会复制数据，此后 data 不再需要
}
```

**进阶：分级缓冲池（按大小分池，减少内存浪费）**

```iFace/tmp/memory.md#L1-1
// 类似 net/http 的 bufioWriterPool 设计
var (
    pool1K  = newPool(1024)
    pool4K  = newPool(4096)
    pool16K = newPool(16 * 1024)
    pool64K = newPool(64 * 1024)
)

func newPool(size int) *sync.Pool {
    return &sync.Pool{
        New: func() interface{} {
            buf := make([]byte, 0, size)
            return &buf
        },
    }
}

func getPool(needed int) *sync.Pool {
    switch {
    case needed <= 1024:  return pool1K
    case needed <= 4096:  return pool4K
    case needed <= 16384: return pool16K
    default:              return pool64K
    }
}
```

**内存优化原理分析：**

| 优化手段 | 原理 | 效果 |
|---------|------|------|
| `sync.Pool` 复用 buffer | 避免每次请求分配新 `[]byte` | 热路径 0 alloc |
| `buf[:0]` 重置而非 nil | 保留底层数组容量，下次 append 不需分配 | 减少扩容 |
| 预分配 4KB 容量 | 覆盖 P95 响应大小，避免 append 触发扩容 | 无扩容分配 |
| 分级缓冲池 | 大小匹配，避免小 buf 被大对象撑大后浪费 | 内存利用率高 |
